'use client';

import { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { Subject, getAttendances, Attendance } from '../../utils/storage';
import { Button } from '../ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '../ui/card';
import { ArrowLeft, QrCode, User, BookOpen, Calendar as CalendarIcon, CheckCircle, XCircle, Clock, School } from 'lucide-react';
import { QRCodeSVG } from 'qrcode.react';

interface SubjectDetailsStudentProps {
  subject: Subject;
  onBack: () => void;
}

export default function SubjectDetailsStudent({ subject, onBack }: SubjectDetailsStudentProps) {
  const { user } = useAuth();
  const [showQR, setShowQR] = useState(false);
  const [attendances, setAttendances] = useState<Attendance[]>([]);

  useEffect(() => {
    const allAttendances = getAttendances();
    const myAttendances = allAttendances.filter(
      a => a.studentId === user?.id && a.subjectId === subject.id
    );
    setAttendances(myAttendances);
  }, [user, subject]);

  const qrData = `${user?.id}|${subject.id}`;

  const presentCount = attendances.filter(a => a.status === 'present').length;
  const lateCount = attendances.filter(a => a.status === 'late').length;
  const totalClasses = attendances.length;

  return (
    <div className="min-h-screen bg-gray-50 pb-20">
      <header className="bg-white border-b sticky top-0 z-10 shadow-sm">
        <div className="container mx-auto px-4 py-4 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <Button variant="ghost" onClick={onBack} size="icon" className="text-primary hover:bg-accent">
              <ArrowLeft className="w-5 h-5" />
            </Button>
            <div>
              <h1 className="text-xl font-black text-primary leading-tight">{subject.name}</h1>
              <p className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">{subject.day} • {subject.time}</p>
            </div>
          </div>
          <Button 
            className="bg-primary hover:bg-primary/90 text-white font-bold rounded-full gap-2 shadow-lg shadow-primary/20"
            onClick={() => setShowQR(!showQR)}
          >
            <QrCode className="h-4 w-4" /> {showQR ? 'Hide Code' : 'Check Attendance'}
          </Button>
        </div>
      </header>

      <main className="container mx-auto px-4 py-8 space-y-8 max-w-5xl">
        {/* Landscape Hero Profile Card */}
        <Card className="bg-primary text-white border-0 shadow-2xl overflow-hidden relative">
          <div className="absolute top-0 right-0 w-64 h-64 bg-white/5 rounded-full -translate-y-1/2 translate-x-1/2 blur-3xl pointer-events-none" />
          <CardContent className="pt-10 pb-10 px-8 relative z-10">
            <div className="flex flex-col md:flex-row items-center gap-8 text-center md:text-left">
              <div className="w-32 h-32 rounded-full bg-white/20 border-4 border-white/30 flex items-center justify-center overflow-hidden shadow-2xl">
                {user?.profilePic ? (
                  <img 
                    src={user.profilePic} 
                    alt={user.name}
                    className="w-full h-full object-cover"
                  />
                ) : (
                  <User className="w-16 h-16 text-white" />
                )}
              </div>
              <div className="flex-1 space-y-2">
                <p className="text-[10px] font-black uppercase tracking-widest text-white/70">Academic Profile</p>
                <h3 className="text-4xl font-black">{user?.name}</h3>
                <div className="flex flex-wrap justify-center md:justify-start gap-4 pt-2">
                  <div className="bg-white/10 px-4 py-2 rounded-xl backdrop-blur-sm">
                    <p className="text-[10px] font-bold uppercase text-white/60 mb-0.5">Student ID</p>
                    <p className="font-bold">{user?.id}</p>
                  </div>
                  <div className="bg-white/10 px-4 py-2 rounded-xl backdrop-blur-sm">
                    <p className="text-[10px] font-bold uppercase text-white/60 mb-0.5">Program</p>
                    <p className="font-bold">{user?.program}</p>
                  </div>
                  <div className="bg-white/10 px-4 py-2 rounded-xl backdrop-blur-sm">
                    <p className="text-[10px] font-bold uppercase text-white/60 mb-0.5">Level</p>
                    <p className="font-bold">Year {user?.year}</p>
                  </div>
                </div>
              </div>
            </div>
          </CardContent>
        </Card>

        {showQR && (
          <Card className="border-primary shadow-2xl animate-in zoom-in-95 duration-300">
            <CardHeader className="bg-primary text-white">
              <CardTitle className="flex items-center gap-2">
                <QrCode className="w-5 h-5" />
                Attendance Verification Code
              </CardTitle>
            </CardHeader>
            <CardContent className="pt-10 pb-10 flex flex-col items-center">
              <div className="p-6 bg-white rounded-3xl shadow-xl border-4 border-primary/10">
                <QRCodeSVG 
                  value={qrData} 
                  size={240}
                  level="H"
                  includeMargin={false}
                  fgColor="#E30613"
                />
              </div>
              <p className="mt-8 text-lg font-bold text-center text-primary uppercase tracking-widest">Show this to your Instructor</p>
              <p className="text-sm text-muted-foreground text-center mt-2 max-w-sm">Scan this code at the start and end of class to accurately log your attendance record.</p>
            </CardContent>
          </Card>
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          <Card className="border-primary/10 shadow-lg">
            <CardHeader className="bg-accent/30 border-b">
              <CardTitle className="text-lg font-bold flex items-center gap-2">
                <BookOpen className="w-5 h-5 text-primary" />
                Subject Logistics
              </CardTitle>
            </CardHeader>
            <CardContent className="pt-6 space-y-6">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <p className="text-[10px] font-bold uppercase text-muted-foreground tracking-widest">Instructor</p>
                  <p className="font-bold text-lg">{subject.teacherName}</p>
                </div>
                <div className="space-y-1">
                  <p className="text-[10px] font-bold uppercase text-muted-foreground tracking-widest">Schedule</p>
                  <p className="font-bold text-lg">{subject.day} at {subject.time}</p>
                </div>
              </div>
              <div className="pt-4 border-t border-primary/5">
                <p className="text-[10px] font-bold uppercase text-muted-foreground tracking-widest mb-1">Status</p>
                <div className="flex items-center gap-2">
                  <div className="h-2.5 w-2.5 rounded-full bg-green-500 animate-pulse" />
                  <span className="font-black text-green-600 uppercase tracking-widest text-sm">Active Session</span>
                </div>
              </div>
            </CardContent>
          </Card>

          <Card className="border-primary/10 shadow-lg">
            <CardHeader className="bg-accent/30 border-b">
              <CardTitle className="text-lg font-bold flex items-center gap-2">
                <CalendarIcon className="w-5 h-5 text-primary" />
                Attendance Statistics
              </CardTitle>
            </CardHeader>
            <CardContent className="pt-6">
              <div className="grid grid-cols-3 gap-4 mb-8">
                <div className="text-center p-4 rounded-2xl bg-green-50 border border-green-100">
                  <p className="text-[10px] font-bold uppercase text-green-600 tracking-widest mb-1">Present</p>
                  <p className="text-3xl font-black text-green-700">{presentCount}</p>
                </div>
                <div className="text-center p-4 rounded-2xl bg-yellow-50 border border-yellow-100">
                  <p className="text-[10px] font-bold uppercase text-yellow-600 tracking-widest mb-1">Late</p>
                  <p className="text-3xl font-black text-yellow-700">{lateCount}</p>
                </div>
                <div className="text-center p-4 rounded-2xl bg-red-50 border border-red-100">
                  <p className="text-[10px] font-bold uppercase text-red-600 tracking-widest mb-1">Sessions</p>
                  <p className="text-3xl font-black text-red-700">{totalClasses}</p>
                </div>
              </div>
              
              {totalClasses > 0 && (
                <div className="pt-6 border-t border-primary/10">
                  <div className="flex items-center justify-between mb-2">
                    <span className="font-bold uppercase tracking-widest text-muted-foreground text-xs">Engagement Score</span>
                    <span className="font-black text-2xl text-primary">
                      {Math.round(((presentCount + lateCount) / totalClasses) * 100)}%
                    </span>
                  </div>
                  <div className="h-3 bg-accent rounded-full overflow-hidden">
                    <div 
                      className="h-full bg-primary" 
                      style={{ width: `${Math.round(((presentCount + lateCount) / totalClasses) * 100)}%` }}
                    />
                  </div>
                </div>
              )}
            </CardContent>
          </Card>
        </div>

        <Card className="border-primary/10 shadow-lg">
          <CardHeader className="bg-accent/30 border-b">
            <CardTitle className="text-lg font-bold flex items-center gap-2">
              <CalendarIcon className="w-5 h-5 text-primary" />
              Detailed History
            </CardTitle>
          </CardHeader>
          <CardContent className="pt-6">
            {attendances.length === 0 ? (
              <div className="text-center py-20 bg-muted/10 rounded-2xl border-2 border-dashed">
                <CalendarIcon className="h-10 w-10 text-muted-foreground/20 mx-auto mb-3" />
                <p className="text-muted-foreground font-medium">No records logged yet for this subject</p>
              </div>
            ) : (
              <div className="space-y-4">
                {attendances
                  .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())
                  .map((attendance) => {
                    const date = new Date(attendance.date);
                    const isPresent = attendance.status === 'present';
                    const isLate = attendance.status === 'late';
                    
                    return (
                      <div 
                        key={attendance.id}
                        className="flex items-center justify-between p-5 border rounded-2xl hover:bg-white hover:shadow-md transition-all group"
                      >
                        <div className="flex items-center gap-4">
                          <div className={`w-12 h-12 rounded-2xl flex items-center justify-center border-2 ${
                            isPresent ? 'bg-green-50 border-green-200' : 
                            isLate ? 'bg-yellow-50 border-yellow-200' : 
                            'bg-red-50 border-red-200'
                          }`}>
                            {isPresent && <CheckCircle className="w-6 h-6 text-green-600" />}
                            {isLate && <Clock className="w-6 h-6 text-yellow-600" />}
                            {!isPresent && !isLate && <XCircle className="w-6 h-6 text-red-600" />}
                          </div>
                          <div>
                            <p className="font-black text-lg">
                              {date.toLocaleDateString('en-US', { 
                                month: 'short', 
                                day: 'numeric',
                                year: 'numeric'
                              })}
                            </p>
                            <p className="text-xs font-bold text-muted-foreground uppercase tracking-widest mt-0.5">
                              {attendance.timeIn ? `Time-in: ${attendance.timeIn}` : 'No timestamp'}
                            </p>
                          </div>
                        </div>
                        <div>
                          <span className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest border-2 ${
                            isPresent ? 'bg-green-100 text-green-700 border-green-200' : 
                            isLate ? 'bg-yellow-100 text-yellow-700 border-yellow-200' : 
                            'bg-red-100 text-red-700 border-red-200'
                          }`}>
                            {attendance.status}
                          </span>
                        </div>
                      </div>
                    );
                  })}
              </div>
            )}
          </CardContent>
        </Card>
      </main>
    </div>
  );
}
