'use client';

import { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { getSubjects, getEnrollments, getUsers, Subject, Enrollment, User } from '../../utils/storage';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '../ui/card';
import { Button } from '../ui/button';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '../ui/tabs';
import { BookOpen, Calendar, Users, ScanLine, LogOut, UserCircle, Clock, School } from 'lucide-react';
import AddSubjectDialog from './AddSubjectDialog';
import TeacherCalendar from './TeacherCalendar';
import SubjectDetails from './SubjectDetails';
import QRScanner from './QRScanner';
import ProfilePage from '../profile/ProfilePage';
import PendingEnrollments from './PendingEnrollments';

export default function TeacherDashboard() {
  const { user, logout } = useAuth();
  const [subjects, setSubjects] = useState<Subject[]>([]);
  const [selectedSubject, setSelectedSubject] = useState<Subject | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [showProfile, setShowProfile] = useState(false);

  useEffect(() => {
    loadSubjects();
  }, [user]);

  const loadSubjects = () => {
    const allSubjects = getSubjects();
    const teacherSubjects = allSubjects.filter(s => s.teacherId === user?.id);
    setSubjects(teacherSubjects);
  };

  const getEnrolledStudentsCount = (subjectId: string) => {
    const enrollments = getEnrollments();
    return enrollments.filter(e => e.subjectId === subjectId && e.status === 'approved').length;
  };

  if (showProfile) {
    return <ProfilePage onBack={() => setShowProfile(false)} />;
  }

  if (selectedSubject) {
    return <SubjectDetails subject={selectedSubject} onBack={() => setSelectedSubject(null)} />;
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <header className="bg-white border-b sticky top-0 z-10 shadow-sm">
        <div className="container mx-auto px-4 py-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div 
              className="w-12 h-12 rounded-xl flex items-center justify-center bg-primary shadow-lg shadow-primary/20"
            >
              <School className="text-white h-7 w-7" />
            </div>
            <div>
              <h1 className="text-xl font-bold text-primary leading-tight">Teacher Portal</h1>
              <p className="text-[10px] uppercase font-bold text-muted-foreground tracking-widest">{user?.name}</p>
            </div>
          </div>
          <div className="flex items-center gap-2">
            <Button variant="outline" onClick={() => setShowProfile(true)} className="hover:text-primary hover:bg-accent border-primary/20">
              <UserCircle className="w-4 h-4 mr-2" />
              Profile
            </Button>
            <Button variant="outline" onClick={logout} className="hover:text-primary hover:bg-accent border-primary/20">
              <LogOut className="w-4 h-4 mr-2" />
              Logout
            </Button>
          </div>
        </div>
      </header>

      <main className="container mx-auto px-4 py-8 max-w-6xl">
        <Tabs value={activeTab} onValueChange={setActiveTab}>
          <TabsList className="grid w-full grid-cols-5 mb-8 bg-white border">
            <TabsTrigger value="dashboard" className="data-[state=active]:text-primary data-[state=active]:font-bold">
              <BookOpen className="w-4 h-4 mr-2" />
              Subjects
            </TabsTrigger>
            <TabsTrigger value="pending" className="data-[state=active]:text-primary data-[state=active]:font-bold">
              <Clock className="w-4 h-4 mr-2" />
              Requests
            </TabsTrigger>
            <TabsTrigger value="calendar" className="data-[state=active]:text-primary data-[state=active]:font-bold">
              <Calendar className="w-4 h-4 mr-2" />
              Schedule
            </TabsTrigger>
            <TabsTrigger value="students" className="data-[state=active]:text-primary data-[state=active]:font-bold">
              <Users className="w-4 h-4 mr-2" />
              Roster
            </TabsTrigger>
            <TabsTrigger value="scanner" className="data-[state=active]:text-primary data-[state=active]:font-bold">
              <ScanLine className="w-4 h-4 mr-2" />
              Scanner
            </TabsTrigger>
          </TabsList>

          <TabsContent value="dashboard" className="space-y-6 animate-in fade-in slide-in-from-bottom-2 duration-300">
            <div className="flex items-center justify-between mb-8">
              <div>
                <h2 className="text-4xl font-black tracking-tight">Active Class Load</h2>
                <p className="text-muted-foreground font-medium italic mt-1">Manage your academic sessions and curriculum</p>
              </div>
              <AddSubjectDialog onSubjectAdded={loadSubjects} />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {subjects.map((subject) => (
                <Card 
                  key={subject.id} 
                  className="cursor-pointer hover:shadow-2xl transition-all border-primary/5 hover:border-primary/30 group relative overflow-hidden h-full flex flex-col"
                  onClick={() => setSelectedSubject(subject)}
                >
                  <div className="h-2 bg-primary w-full" />
                  <CardHeader className="pb-4">
                    <CardTitle className="text-2xl font-black group-hover:text-primary transition-colors">{subject.name}</CardTitle>
                    <CardDescription className="font-bold flex items-center gap-1.5 text-muted-foreground uppercase text-[10px] tracking-widest">
                       <Calendar className="h-3 w-3 text-primary" /> {subject.day} <span className="text-primary">•</span> {subject.time}
                    </CardDescription>
                  </CardHeader>
                  <CardContent className="flex-1 flex flex-col justify-end">
                    <div className="pt-4 border-t border-primary/5 mt-auto flex justify-between items-center">
                      <span className="text-xs font-bold uppercase text-muted-foreground tracking-widest">Enrollment</span>
                      <span className="font-black text-xl text-primary">{getEnrolledStudentsCount(subject.id)}</span>
                    </div>
                  </CardContent>
                </Card>
              ))}
              
              {subjects.length === 0 && (
                <Card className="col-span-full border-dashed border-2 bg-accent/20">
                  <CardContent className="flex flex-col items-center justify-center py-20">
                    <BookOpen className="w-16 h-16 text-primary/20 mb-6" />
                    <h3 className="text-2xl font-bold mb-2">No subjects found</h3>
                    <p className="text-muted-foreground max-w-sm text-center mb-8">You haven't added any subjects to your portfolio yet. Click "Add Subject" to begin.</p>
                  </CardContent>
                </Card>
              )}
            </div>
          </TabsContent>

          <TabsContent value="pending" className="animate-in fade-in slide-in-from-bottom-2 duration-300">
            <PendingEnrollments teacherId={user!.id} />
          </TabsContent>

          <TabsContent value="calendar" className="animate-in fade-in slide-in-from-bottom-2 duration-300">
            <TeacherCalendar subjects={subjects} />
          </TabsContent>

          <TabsContent value="students" className="animate-in fade-in slide-in-from-bottom-2 duration-300">
            <Card className="border-primary/10 shadow-lg">
              <CardHeader className="bg-primary/5 border-b">
                <CardTitle className="text-lg font-bold">Class Roster Overview</CardTitle>
                <CardDescription>Comprehensive list of students across all your active subjects</CardDescription>
              </CardHeader>
              <CardContent className="pt-6">
                <AllStudentsView teacherSubjects={subjects} />
              </CardContent>
            </Card>
          </TabsContent>

          <TabsContent value="scanner" className="animate-in fade-in slide-in-from-bottom-2 duration-300">
            <QRScanner />
          </TabsContent>
        </Tabs>
      </main>
    </div>
  );
}

function AllStudentsView({ teacherSubjects }: { teacherSubjects: Subject[] }) {
  const [students, setStudents] = useState<User[]>([]);

  useEffect(() => {
    const enrollments = getEnrollments();
    const users = getUsers();
    
    const subjectIds = teacherSubjects.map(s => s.id);
    const enrolledStudentIds = enrollments
      .filter(e => subjectIds.includes(e.subjectId) && e.status === 'approved')
      .map(e => e.studentId);
    
    const uniqueStudentIds = Array.from(new Set(enrolledStudentIds));
    const enrolledStudents = users.filter(u => uniqueStudentIds.includes(u.id));
    
    setStudents(enrolledStudents);
  }, [teacherSubjects]);

  if (students.length === 0) {
    return (
      <div className="text-center py-20 bg-muted/20 rounded-xl border-2 border-dashed">
        <Users className="h-10 w-10 text-muted-foreground/20 mx-auto mb-3" />
        <p className="text-muted-foreground font-medium">No students enrolled in your subjects yet</p>
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
      {students.map((student) => (
        <div key={student.id} className="flex items-center gap-4 p-4 border rounded-2xl hover:bg-primary/5 transition-all group">
          <div className="w-14 h-14 rounded-full bg-primary/10 flex items-center justify-center border-2 border-white shadow-sm overflow-hidden">
            {student.profilePic ? (
              <img src={student.profilePic} alt={student.name} className="w-full h-full object-cover" />
            ) : (
              <span className="text-primary font-bold text-lg">{student.name.charAt(0)}</span>
            )}
          </div>
          <div className="flex-1">
            <p className="font-bold group-hover:text-primary transition-colors">{student.name}</p>
            <p className="text-xs font-bold text-muted-foreground uppercase tracking-widest">{student.program} • Year {student.year}</p>
          </div>
          <div className="text-[10px] font-black uppercase text-primary bg-primary/10 px-3 py-1 rounded-full">{student.id}</div>
        </div>
      ))}
    </div>
  );
}
