'use client';

import { useState } from 'react';
import { loginUser } from '../../utils/storage';
import { useAuth } from '../../contexts/AuthContext';
import { Button } from '../ui/button';
import { Input } from '../ui/input';
import { Label } from '../ui/label';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '../ui/card';
import { toast } from 'sonner';

interface LoginPageProps {
  onSwitchToSignup: () => void;
}

export default function LoginPage({ onSwitchToSignup }: LoginPageProps) {
  const [id, setId] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    const user = loginUser(id, password);
    if (user) {
      login(user);
      toast.success(`Welcome back, ${user.name}!`);
    } else {
      toast.error('Invalid USN/EMP or password');
    }

    setLoading(false);
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-4 bg-[#f5f5f5]">
      <Card className="w-full max-w-md border-primary/10 shadow-xl">
        <CardHeader className="space-y-2 text-center">
          <div className="flex justify-center mb-4">
            <div 
              className="w-20 h-20 rounded-full flex items-center justify-center bg-primary"
            >
              <span className="text-white text-2xl font-bold">SMS</span>
            </div>
          </div>
          <CardTitle className="text-2xl font-bold text-primary">School Management System</CardTitle>
          <CardDescription>Sign in to your account</CardDescription>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit} className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="id">USN / Employee Number</Label>
              <Input
                id="id"
                type="text"
                placeholder="Enter your USN or EMP number"
                value={id}
                onChange={(e) => setId(e.target.value)}
                required
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="password">Password</Label>
              <Input
                id="password"
                type="password"
                placeholder="Enter your password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                required
              />
            </div>
            <Button 
              type="submit" 
              className="w-full bg-primary hover:bg-primary/90 text-white font-bold" 
              disabled={loading}
            >
              {loading ? 'Signing in...' : 'Sign In'}
            </Button>
            <div className="text-center text-sm">
              <span className="text-muted-foreground">Don't have an account? </span>
              <button
                type="button"
                onClick={onSwitchToSignup}
                className="font-medium hover:underline text-primary"
              >
                Sign up
              </button>
            </div>
            <div className="text-center text-xs text-muted-foreground mt-4 p-3 bg-accent rounded-md">
              <p className="font-medium mb-1">Default Login Credentials:</p>
              <p>Admin: admin / ADMIN@2026</p>
            </div>
          </form>
        </CardContent>
      </Card>
    </div>
  );
}